SELECT ,
       u.username
FROM long_term_lease l
LEFT JOIN user u ON l.user_id = u.id
WHERE l.seat_id = #{seatId}
  AND l.status IN (2, 5, 6)
  AND DATE(l.start_date) <= #{date}
  AND DATE(l.end_date) >= #{date}
ORDER BY l.start_date ASC

SELECT 
FROM long_term_lease l
WHERE l.user_id = #{userId}
  AND l.status IN (2, 5, 6)
  AND l.start_date <= #{endDate}
  AND l.end_date >= #{startDate}
ORDER BY l.start_date ASC

SELECT 
FROM long_term_lease l
WHERE l.status IN (2, 5, 6)
  AND l.start_date <= #{endDate}
  AND l.end_date >= #{startDate}
ORDER BY l.start_date ASC

